def partGroupIdList(cartridge) {
    my grouplist = List();
    my groupid = EnvValue('CO.GroupId'); /* von PO gesetzt */
    my list = List();
    if (StrLen(groupid) eq 0 ) {
      /* direktes CO printing */
	    list = GetComponentList();
	    if (cartridge ne 'all') { 
	      list = FilterList(list,'element',`cartridge ne GetCartridge(element);`);
	    }

	    for (my part : list) {
	      groupid = Feature(part, '_PXi_permanent_group_id');
	      if (groupid ge 0) {
	      	ListAdd(grouplist,groupid);

		  }
	    }
	    grouplist = UniqueList(grouplist);  
    } else { 
      /* von PO gesetzt */
      if (cartridge eq EnvValue('CO.Print.Cartridge')) {
        grouplist = List(groupid);
      }
    }
    return grouplist;
 }

def printOverview(caller,montage,groupcounter) {
    my overview = false;
    overview = (caller eq 'co' and EndsWith(montage,'3D') and groupcounter eq 1) or (caller eq 'po' and montage eq '3D');
    return overview; 
  }

def printFormatPathCO() {
    my format = '';
    if (EnvValue('PO2.PrintLayoutPDF') eq 'US-Letter') {
       format = 'usa/';
    }
    return format; 
  }

def printPositionListCO() {
    my printgrouplist = List();
    my positionenlist = List();
    my list = GetComponentList();
    my group = '';
    my pos = '';
    my id = '';
    my grouplist = List();
    my groupidlist = List();
    my groupnewlist = List();
    my positionexistlist = List();
    my printidlist = List();
    my printlist = List();
    my allidlist = List();
    my j = 0;
    my documentpos = FromJson(NodeValue(NamedNode('documentsettings'),'configdocument'))['name','position_number']['value'];
    my positions = FromJson(NodeValue(NamedNode('documentsettings'),'configpart'));
    my positionidlist = List();

    for (my i : IndexList(Size(positions))) {
      positionidlist[i] = positions[i][0];
    }
    for (my i : IndexList(Size(list))) {
       my groupid = USMPartGroupId(list[i]);
       if (not InList(groupidlist,groupid)) {
         groupidlist = ListAdd(groupidlist,groupid);
         grouplist[j][0] = groupid;
         grouplist[j][1] = 'Pos. ' ++ documentpos ++ '.' ++ (j+1);
         grouplist[j][2] = GetCartridge(list[i]);
         grouplist[j][3] = 'Neue Konfiguration_' ++ (j+1);
         j = j + 1;
       }  
     } 
     if (Size(positionidlist) ne 0) {
     /* PO hat aber min. 1 Position */
       for (my i : IndexList(Size(positions))) {
          pos = positionidlist[i];
          if (InList(pos, groupidlist)) {
            positionexistlist = ListAdd(positionexistlist,pos);
          }
       }

       for (my i : IndexList(Size(groupidlist))) {
          group = groupidlist[i];
          if (not InList(group, positionidlist)) {
            groupnewlist = ListAdd(groupnewlist,group);
          }
       }
       printlist = JoinList(grouplist,positions);
       allidlist = JoinList(groupnewlist,positionexistlist);
       for (my i : IndexList(Size(printlist))) {
        for (my j : IndexList(Size(allidlist))) {
         id = allidlist[j];
         if (printlist[i][0] eq id and not InList(printidlist,id)) {
           printidlist = ListAdd(printidlist,id);
           printgrouplist = ListAdd(printgrouplist,printidlist[i]);
         }
        }
       }

    } else {
      printgrouplist = grouplist;
    }

    return grouplist;
   }

def groupIdPartList(groupid) {
  	my n = '_PXi_permanent_group_id';
  	my partlist = FilterList(GetComponentList(),'element',`groupid ne Feature(element, n);`);
  	/*
    my partlist = FilterList(GetComponentList(),'element',`groupid ne USMPartGroupId(element);`);
    */

    return partlist;
 }

def setFirstPrintZone(cartridge) {
	  my ohnezones  = List();
	  my regal_ids = call partGroupIdList(cartridge);
	  my zones = USMGetPrintZones();
	  my zone_ids = List();
	  for (my zone : zones) {
	    zone_ids = ListAdd(zone_ids, zone['groupid']);
	  }
	  for (my id : regal_ids) {
	    if (not InList(zone_ids, id)) {
	      ohnezones = ListAdd(ohnezones, id);
	    }
	  } 
	  return ohnezones;
		}

def checkFullpageCount(pagecount_assembling, montage) {
    my pages = pagecount_assembling;
    if (montage eq '2D_and_3D') {
      pages = pages + 1;
    } else if (montage eq 'only_3D') {

      pages = 1;
    }
    return pages;
 }

def checkFullpageCountCO(positionen,montage,inos) {
    my pages = 0; 
    my groupId = '';
    my groupcartridge = '';
    my zoneId = '';
    my groups = positionen;
    my grouppages = Size(positionen); /* jede Gruppe hat sicher schon mal eine page */
    my zones = USMGetPrintZones();
    my hallerIds = 0;
    my primoIds = 0;
    my tischIds = 0;
    my zonepages = 0;
    for (my group : groups) {
      groupId = group[0];
      groupcartridge = group[2];
      hallerIds = 0;
      primoIds = 0;
      tischIds = 0;
      zonepages = 0;
      for (my zone : zones) {
        zoneId = zone['groupid'];
        if (zoneId eq groupId) {
          if (groupcartridge eq 'usm_hallertisch' or groupcartridge eq 'usm_kitos') {
            tischIds = tischIds + 1;
          }
          if (groupcartridge['cartridge'] eq 'usm_haller') {
            hallerIds = hallerIds + 1;
          }
          if (groupcartridge['cartridge'] eq 'usm_primo') {
            primoIds = primoIds + 1;
          }
        }
      }
      if (hallerIds gt 1) {
        /* erst wenn mehr als eine Zone definiert ist, braucht es zusaezliche Seiten */
        zonepages = zonepages + (hallerIds -1);
      }
      if (primoIds gt 1) {
        /* erst wenn mehr als eine Zone definiert ist, braucht es zusaezliche Seiten */
        zonepages = zonepages + (primoIds -1);
      }
      if (tischIds gt 0) {
      /* Tische brauchen pro Zone immer eine zusaezliche Seite */
        zonepages = zonepages + tischIds;
      }
      if (Bool(inos)) {
        grouppages = grouppages + Size(call inosMontageZones(groupId));
      }
      grouppages = grouppages + zonepages; 
    }
    pages = pages + grouppages;
    if (montage eq '2D_and_3D') {
      pages = pages + 1;
    } else if (montage eq 'only_3D') {
      pages = 1;
    } else if (montage eq '2D_only') {
      pages = pages;
    } else if (montage eq 'currentView') {
      pages = 1;
    }
    return pages;
  }

def transparentPrintHallerE(part) {
      my active = false;
      my transparent1 = IsSubTypeOf(part,'verkleidung') or IsSubTypeOf(part,'zwischenwand') or IsSubTypeOf(part,'ct_tablar');
      my transparent2 = IsSubTypeOf(part,'ct_EinsaetzeAusruestung') or IsSubTypeOf(part,'metalltuer'); 
      my transparent3 = IsSubTypeOf(part,'beschlag') or IsSubTypeOf(part,'stdklemmhalter') or IsSubTypeOf(part,'ct_inosBoxKonzept');
      /* my transparent4 = not IsSubTypeOf(part,'rohrgriff') and GetTypeName(part) ne 'gCE_ContextZone'; */
      active = transparent1 or transparent2 or transparent3 ;
      return active;
   }

def getPrintZones() {
		my cc = ChangeCount('NC,NCE,CM,CEM', false);
	    if (cc != PRINTZONES_CC or PRINTZONES == null) {
	    	PRINTZONES_CC = cc;
	    	PRINTZONES = USMGetPrintZones();
	    }
	    return PRINTZONES;
	};

def groupIdZones(groupid) {
    my groupzones = FilterList(USMGetPrintZones(),'zone',`zone['groupid'] ne groupid;`);
    return groupzones;
  }

def printZoneTooBig() {
my conflicts = List();
my toobigs = List();
my max = 320;
my zones = USMGetPrintZones();
zones = FilterList(zones,'element',`element['cartridge'] ne 'usm_haller';`);
for (my zone : zones) {
  if (zone['length'] gt max or zone['depth'] gt max) {
    /* toobig = ListAdd(toobig,zone['parts'][0]); */
    toobigs = ListAdd(toobigs,zone['name']);
  }  
}
for (my toobig : toobigs) {
    conflicts = JoinList(conflicts, call groupIdVolumeList(toobig));
}
return conflicts;
}

def turnHallerMontageLayout(zone) {
		my turn = false;
		if (zone['length'] gt 300) {
		  turn = true;
		}
		return turn;
		}

def groupIdMaterialCode(cartridge,groupid) {
    my materialcode = '';
    my materials = List();
    my metalls =List();
    my glasses =List();
    my max = 0;
    my size = 0;
    my parts = call groupIdPartList(groupid);
    if (cartridge eq 'usm_haller') {
      metalls = FilterList(parts,'element',`not PropertyActive(element, 'metallverkleidungsFarbe');`);
      glasses = FilterList(parts,'element',`not IsSubTypeOf(element,'glasverkleidung');`);
      if (Size(metalls) gt Size(glasses)) {
        materials = FeatureValuesFromPartList(metalls,'Metallfarbe');
        for (my material : materials) {
           size = Size(FilterList(metalls,'element',`Feature(element, 'Metallfarbe') ne material;`));
           if (size gt max) {
             max = size;
             materialcode = material;
           }
        }
      } else {
        materialcode = '80';
      }
    }
    return materialcode;
  }

def projectInfoOffsetCO(pos) {
			my offsetposy = 0;
			my projectnamelength = StrLen(call printProjectInfoCO('nodename'));

			if (projectnamelength GT 27) {
				offsetposy = 16;
			}
			if (projectnamelength GT 54) {
				offsetposy = 32;
			}
			offsetposy;
			if (pos eq 'id') {
				my projectidlength = StrLen(call printProjectInfoCO('project_id'));

	      if (projectidlength GT 27) {
	        offsetposy = offsetposy + 16;
	      }
	      if (projectidlength GT 54) {
	        offsetposy = offsetposy + 32;
	      }
      }
      offsetposy;
			return offsetposy;
		}

