			my string = '';
			my infonode = FromJson(NodeValue(NamedNode('documentsettings'),'projectinfos'));
			string = infonode['name',mode]['value'];
			return string;
		}

def printDocumentInfoCO(mode) {
      my string = '';
      my infonode = FromJson(NodeValue(NamedNode('documentsettings'),'configdocument'));
      string = infonode['name',mode]['value'];
      string = Trim(string);
      return string;
    }

def printDeliverydateCO(mode) {
			my delivery = '';
			my date = '';
			my infonode = FromJson(NodeValue(NamedNode('documentsettings'),'projectinfos'));
			my printsetting_customer = infonode['name','printsetting_customer']['value'];

			if (printsetting_customer) {
				date = infonode['name','deliverydate_customer']['value'];
			} else {
				date = infonode['name','delivery_date']['value'];
			}

			if (mode EQ 'title') {
				if (StrLen(date) gt 2 AND not printsetting_customer) {
					delivery = delivery ++ Localize('Lieferdatum ab Werk');
				} else if (StrLen(date) gt 2 AND printsetting_customer) {
					delivery = delivery ++ Localize('Lieferdatum an Kunde');
				}
			} else if (mode EQ 'date') {
				if (IsCalendarWeek(date)) {
					delivery = delivery ++ Localize('Kalenderwoche') ++ ' ' ++ GetWeek(date);
				} else {
					delivery = delivery ++ FormatDateSystem(date,FALSE);
				}
			}
			return delivery;
		}

def printDateOrdernumberCO(mode) {
			my string = '';
			my infonode = FromJson(NodeValue(NamedNode('documentsettings'),'projectinfos'));
			my purchaseorder = infonode['name','purchaseorder']['value'];
			my printdate = FormatDateSystem(ActualDate(), FALSE);

			if (mode EQ 'actualdate') {
				string = string ++ printdate;
			} else if (mode EQ 'ordernumber') {
				if (StrLen(purchaseorder)) {
					string = string ++ purchaseorder;
				}
			}
			return string;
		}

def printPartnerAdressCO(short,underlined) {
      my partneraddress = '';
      my streetaddress = '';
      my location = '';
      my infonode = FromJson(NodeValue(NamedNode('documentsettings'),'partneraddress'));
      my companyname = infonode['name','company_name']['value'];
      my streetname = infonode['name','street']['value'];
      my streetnumber = infonode['name','street_number']['value'];
      my zipcode = infonode['name','zip']['value'];
      my city = infonode['name','city']['value'];
      my state = infonode['name','state']['value'];
      my country_iso = infonode['name','country']['value'];
      my country = Localize(countrycodes['iso',country_iso]['name']);
      my layouttyp = infonode['name','layouttyp']['value'];

      if ( not Bool(StrLen(layouttyp)) ) {
        layouttyp = 'europe';
      }
      /* Street Layout */
      if (layouttyp eq 'europe') {
        streetaddress = streetname ++ ' ' ++ streetnumber;
      } else if (StrLen(streetnumber) gt 0) {
        if (layouttyp eq 'france') { 
          streetaddress = streetnumber ++ ', ' ++ streetname;
        } else {
          streetaddress = streetnumber ++ ' ' ++ streetname;
        }
      }
      /* Location Layout */
      location = zipcode ++ ' ' ++ city;
      if (layouttyp eq 'usa') {
        if (StrLen(state) gt 0) {
          location = city ++ ' ' ++ state ++ ' ' ++ zipcode;
        } else {
          location = city ++ ' ' ++ zipcode;
        }
      }

      /* Address Layout */
      partneraddress = companyname++', '++streetaddress++', '++location;

      if (StrLen(partneraddress) gt 6) {
        /* Long-Address Layout */       
        if (not Bool(short)) {
          partneraddress = partneraddress++', '++country;
        }
        /* Underlined Address Layout */
        if (underlined) {
          partneraddress = StrReplace(partneraddress, ' ', '_');
        }
      } else {
        /* no Address entries */
        partneraddress = '';
      }
      return partneraddress;
    }

def printPartnerCommunicationCO(fontactive) {
			my communication = '';
			my phonenumber_central = '';
			my list = List();
			my infonode = FromJson(NodeValue(NamedNode('documentsettings'),'partneraddress'));
			my website = infonode['name','website']['value'];

			if (StrLen(infonode['name','tel_central']['value'])) {
				phonenumber_central = Localize('Telefon') ++ ' ' ++ infonode['name','tel_central']['value'] ++ ', ';
			}

			my email = '';
			my company_email = infonode['name','email_company']['value'];
			if (StrLen(company_email)) {
				email = company_email++', ';

				/* if the control characters for the font are transcribed for the output,
				a second '@' has to be added */
				if (fontactive) {
					list = StringToList(email,'@');
					email = list[0] ++ '@@'++ list[1] ++ ', ';
				}

			}
			communication = phonenumber_central ++ email ++ website;
			return communication;
		}

def setAddrLayoutType(adrnode,country) {
      my layouttyp = adrnode['name','layouttyp']['value'];   
      if (StrLen(layouttyp) eq 0) {
        layouttyp = 'europe';
        if (country eq 'FR') { 
        layouttyp = 'france';
       }else if (country eq 'US') {
        layouttyp = 'usa';
       }
      }
      return layouttyp;
     }

def printOrderAddressCO(){
      my orderaddress = '';
      my adrnode = FromJson(NodeValue(NamedNode('documentsettings'),'cust_orderaddress'));
      my country_iso = adrnode['name','country']['value'];
      my country = Localize(countrycodes['iso',country_iso]['name']); 
      my projectinfos = FromJson(NodeValue(NamedNode('documentsettings'),'projectinfos'));
      my layouttyp = projectinfos['name','printsetting_layouttyp']['value'];
      my street = Trim(adrnode['name','street']['value']);
      /* FROM SF CRM multiple lines inside street with ; separator */
      street = StrReplace(street, ';', '@n');
      my house =  adrnode['name','street_number']['value'];
      my number = StrLen(house) gt 0;
      my zip = adrnode['name','zip']['value'];
      my city = adrnode['name','city']['value'];
      my state = adrnode['name','state']['value'];

      my pob = Trim(adrnode['name','pob']['value']);

      my tabl= List();
      tabl[0] = adrnode['name','company_name']['value'];
      tabl[1] = adrnode['name','company_addition']['value'];
      my salute = call salutationChoice('name', adrnode['name','salutation']['value']);
      if(StrLen(salute) gt 0){
      	tabl[2] = salute ++' ' ++ adrnode['name','first_name']['value'] ++ ' ' ++ adrnode['name','last_name']['value'];
     	}
      else{
	      tabl[2] = adrnode['name','first_name']['value'] ++ ' ' ++ adrnode['name','last_name']['value'];
      }
      tabl[2] = Trim(tabl[2]);

      if (number) {
        if (layouttyp eq 'europe') {
          tabl[3] = street ++ ' ' ++ house;
        } else if (layouttyp eq 'france') {
          tabl[3] = street ++ ', ' ++ house;
        } else {
          tabl[3] = house ++ ' ' ++ street;
        }
      } else {
        tabl[3] = street;
      }
      tabl[3] = Trim(tabl[3]);
      tabl[4] = adrnode['name','address_addition']['value'];
      if (layouttyp ne 'usa' and StrLen(pob) gt 0) {
        tabl[5] = Localize('POB') ++' '++ pob ++ '@n' ++ zip ++ ' ' ++ city ++ '@n' ++ country;
      } else if (layouttyp ne 'usa' and StrLen(pob) eq 0) {
        tabl[5] = zip ++ ' ' ++ city ++ '@n' ++ country;
      }
      else if (layouttyp eq 'usa' and StrLen(pob) gt 0) {
        tabl[5] = Localize('POB') ++' '++ pob ++ '@n'++ city ++ ' ' ++ state ++ ' ' ++ zip;
      }
      else {
        tabl[5] = city ++ ' ' ++ state ++ ' ' ++ zip;
      }
      tabl[5] = Trim(tabl[5]);

      for (my zeile : tabl) {
        if (StrLen(zeile) gt 3) {
          orderaddress = '@/100' ++ orderaddress ++ zeile ++ '@n';
        }
      }
      ;
      return orderaddress;
    }

def printMaterialAsListCO(groupid,param_cartridge) {
			my materiallist = List();
			my cartridge = param_cartridge;
			my elements_by_groupid = call groupIdPartList(groupid);
			my colorfeatures = List();
			my inos_elements = List();
			my glashalter = List();
			my glasverkleidung = List();
			my colorlist_compressed = List();

			if (InList(List('usm_hallertisch','usm_kitos'),cartridge)) {
				return materiallist;
			} else {
				if (cartridge EQ 'usm_haller') {
					ListAdd(colorfeatures,Dictionary(List('name','cartridge','headerindex'),List('Metallfarbe',cartridge,1)));
					ListAdd(colorfeatures,Dictionary(List('name','cartridge','headerindex'),List('f_inosBoxMaterial','INOS',2)));
					ListAdd(colorfeatures,Dictionary(List('name','cartridge','headerindex'),List('f_inosBoxUnterteilungMaterial','INOS',2)));
					ListAdd(colorfeatures,Dictionary(List('name','cartridge','headerindex'),List('Schalentypmaterial','INOS',2)));
					ListAdd(colorfeatures,Dictionary(List('name','cartridge','headerindex'),List('Beschlaegematerial','pty_Beschlaegematerial',3)));
					ListAdd(colorfeatures,Dictionary(List('name','cartridge','headerindex'),List('Glasmaterial',cartridge,1)));
				} else if (cartridge EQ 'usm_primo') {
					ListAdd(colorfeatures,Dictionary(List('name','cartridge','headerindex'),List('f_primoMaterial',cartridge,4)));
					ListAdd(colorfeatures,Dictionary(List('name','cartridge','headerindex'),List('f_primoMaterialBi',cartridge,4)));
				}
				my elements = List();
				for (my colorfeature : colorfeatures) {
					elements = JoinList(elements,FilterList(elements_by_groupid,'element',`NOT HasFeature(element,colorfeature['name']);`));
				}
				colorlist_compressed = call colorListCOCompressed(elements,colorfeatures);
				materiallist = Sort(colorlist_compressed,`element1['colorcode'] GT element2['colorcode'] ? 1 : (element1['colorcode'] LT element2['colorcode'] ? -1 : 0);`);
				return materiallist;
			}
		}

def printSchlossListCO(groupid) {
      my schlossprintstring = '';
      my schlosslist = List();
      my list = List();
      my schlossname = Localize('Schloss-Nr');
      my filename = EnvValue('PO2.VUH.FullPath');
      my list = Load(filename, 'header', 'moebel');
      list = AsList(list);
      if (Size(list) gt 0) {
        schlossprintstring = '@n';
        schlosslist = CompressTable(list,List('static','article','locknr','lockid'),List('count'));
        for (my schloss : schlosslist) {
          if (schloss['staticid'] eq groupid) {
            schlossprintstring = schlossprintstring ++ schlossname ++ ' ' ++ schloss['locknr'] ++ '@n';
          }
        }
        schlossprintstring;
      }
      return schlossprintstring;
    }

def colorListCOCompressed(elements,colorfeatures) {
        my colorlist_compressed = List();
        my colorcode = '';
        my colordescription = '';
        my colorlist = List();
        my first = '';
        for (my element : elements) {
          for (my feature : colorfeatures) {
            if (HasFeature(element,feature['name'])) {
              colorcode = Feature(element,feature['name']);
              if (colorcode EQ 'glas_haller') {
                colorcode = '80';
              }
              if (colorcode EQ 99) {
                colordescription = Localize('Sonderfarbe');
              } else {
                colordescription = colornames['Farbcode',colorcode]['Bezeichnung_'++UpperCase(EnvValue('DYNAMIC.Language'))];
                first = UpperCase(SubStr(colordescription,0,1));
                colordescription = first ++ SubStr(colordescription,1);
              }
              ListAdd(colorlist,Dictionary(List('colorcode','colordescription','cartridge','headerindex'),List(colorcode,colordescription,feature['cartridge'],feature['headerindex'])));
            }
          }
        } 
        colorlist_compressed = CompressTable(colorlist,List('cartridge','colorcode'),List());
       return colorlist_compressed;
    }

def printHeaderMaterialsCO(groupid,cartridge) {
      my materiallist = List();
      my string = '';
      my empty = '';
      my max = 11;
      my rows = List();
      my size = 0;
      my schlossnummern = '';
      my cartridges = List('usm_haller','usm_primo');
      my groupids = List();
      my ids_loop = List();
      my list = List();
      my dictionary = List();
      if (cartridge eq 'overview') {
        for (my i : List(0,1)) {
          ids_loop = call partGroupIdList(cartridges[i]);
          for (my j : IndexList(Size(ids_loop))) {
            dictionary = Dictionary(List('groupid','cartridge'),List(ids_loop[j],cartridges[i]));
            ListAdd(groupids,dictionary);
          }
        }
      } else {
         groupids = List(Dictionary(List('groupid','cartridge'),List(groupid,cartridge)));
      }
      my materials = List();
      for (my gid : groupids) {
        materials = JoinList(materials,call printMaterialAsListCO(gid['groupid'],gid['cartridge']));
      }
      materials = CompressTable(materials,List('cartridge','colorcode'),List());
      materials = SortByValue(materials,`element['headerindex'];`);
      my materials_sorted = List();
      my cartridgelist = CompressTable(materials,List('cartridge'),List());

      if (cartridge EQ 'usm_haller') {
        cartridgelist = FilterList(cartridgelist,'row',`row['cartridge'] eq 'usm_primo';`);
      } else if (cartridge EQ 'usm_primo') {
        cartridgelist = FilterList(cartridgelist,'row',`row['cartridge'] ne 'usm_primo';`);
      } 
      my temp = List();
      for (my type : cartridgelist) {
        temp = FilterList(materials,'row',`row['cartridge'] NE type['cartridge'];`);
        temp = Sort(temp,`element1['colorcode'] GT element2['colorcode'] ? 1 : (element1['colorcode'] LT element2['colorcode'] ? -1 : 0);`);
        materials_sorted = JoinList(materials_sorted,temp);
      }
      materials_sorted;

      my cartridge_materials = List();
      for (my type : cartridgelist) {
        string = string ++ '@n' ++ '@-@-' ++ Localize(type['cartridge']) ++ '@+@+';
        cartridge_materials = FilterList(materials_sorted,'row',`row['cartridge'] NE type['cartridge'];`);
        cartridge_materials = FilterList(cartridge_materials,'row',`row['colordescription'] EQ '';`);
        for (my material : cartridge_materials) {
          string = string ++ '@n' ++ material['colorcode'] ++ ' ' ++ material['colordescription'];
        }
      }
      return string;
    }

def printDynamicHeaderMaterialsCO(groupid,column) {
      my string = '';
      my rows = List();
      my size = 0;
      my max = 11; /* maximale Anzahl Zeilen */
      my cartridge = '';
      my zones = List();
      my parts = List();
      my schlossnummern = List();
      my empty = List();
      if (groupid ne 'all') {
        zones = call groupIdZones(groupid);  
        cartridge = zones[0]['cartridge'];
        if (StrLen(cartridge) eq 0) {
          parts = call groupIdPartList(groupid);
          cartridge = GetCartridge(parts[0]);
        }
      } else {
        cartridge = 'overview';
      }

      string = call printHeaderMaterialsCO(groupid,cartridge);

      if (cartridge eq 'usm_haller') {
        schlossnummern = call printSchlossListCO(groupid);
        if (StrLen(schlossnummern) gt 3) {
          string = string ++ '@n' ++ '@-@-' ++ Localize('Schlossnummer') ++ '@+@+';
          string = string ++ schlossnummern;
        }
      }
      /* zuschneiden der List fuer 1. Reihe und 2. Reihe */
      rows = StringToList(string,'@n');
      empty = ListRemoveFirst(rows);
      size = Size(rows);
      if (column eq 'first' and size gt max) {   
        string = '';
        for (my i : IndexList(max)) {
          string = string ++ '@n' ++ rows[i];
        }
      } else if (BeginsWith(column,'second') and size gt max) {    
        if (size le 2*max) {
          string = '';
          for (my i : call indexList(max, 1, size-max)){
            string = string ++ '@n' ++ rows[i];
          }
        } else if (size gt 2*max) {
          string = '';
          for (my i : call indexList(max, 1, max - 1)) { 
            string = string ++ '@n' ++ rows[i];
          }
          string = string ++ '@n' ++ Localize('...');
        }

      } else if (BeginsWith(column,'second') and size lt max) {
        string = '';
      } 
      return string;
    }

def printHeaderMaterialsCO2(prodline,groupid,column) {
		   my string = '';
		   my product = prodline;
		   if (prodline eq 'usm_haller') {
		      product = 'usm_halleraddons';
		   }
		   string = call printHeaderMaterialsCO(product,List(Dictionary(List('groupid','cartridge'),List(groupid,prodline))),column);
		   return string;
		}

def printPartInfoCO(groupid,mode){
      my string = '';
      my configid = groupid;
      my list = FromJson(NodeValue(NamedNode('documentsettings'),'configpart'));
      list = FilterList(list,'row',`row[0] NE configid;`);
      if (Size(list) eq 0) {
        configid = groupid;
        list = call printPositionListCO();
        list = FilterList(list,'row',`row[0] NE configid;`);
      }

      list = list[0];

      if (mode eq 'posnr') {
        string = list[1];
      } else if (mode eq 'nodename') {
        string = list[3];
      } else if (mode eq 'furnituretype') {
        string = list[2];
      }
      return string;
    }

def doCartridgePrint(caller,prodline,montage,cartridge) {
      my doprint = false;
      my docartridge = prodline eq cartridge;
      if (caller eq 'co') {
        doprint = docartridge and BeginsWith(montage,'2D');
      } else if (BeginsWith(caller,'po')) {
        doprint = docartridge and montage eq cartridge;
      }
      return doprint;
    }

def montageZones(groupid) {
			my zones = call groupIdZones(groupid);
			 if (not Bool(Size(zones))){
			   zones = List(1);
			} 

			return zones;
	  }

def inosMontageZones(groupid) {
			my inoszones = List();
			my zones = call montageZones(groupid);
			my parts = call groupIdPartList(groupid);
			if (FilterList(parts,'element',`not IsSubTypeOf(element,'ct_inosBox');`)[0]) {
			  inoszones = zones;
			}	
			return inoszones;
	  }

def montageZonesFuss(groupid) {
      my fusszones = List();
      my fuesse = List();
      my parts = call groupIdPartList(groupid);
      my bodenelemente = FilterList(parts,'element',`not IsSubTypeOf(element,'bodenelement');`);
      for (my i : IndexList(Size(bodenelemente))) {
        fuesse[i] = GetTypeName(bodenelemente[i]);
      }
      fuesse = UniqueList(fuesse) ;
      /* wenn es mehr als eine Sorte Fuesse gibt */
      if (Size(fuesse) gt 1) {
        fusszones = call groupIdZones(groupid);
        if (Size(fusszones) eq 0) {
        /* wenn keine Printzone gesetzt ist */
          fusszones = List(0);
        }
      }
      return fusszones;
    }

def montageZonesHallerE(groupid) {
      my hallerEzones = List();
      my zones = call montageZones(groupid);
      my parts = call groupIdPartList(groupid);
      parts = FilterList(parts,'element',`not IsSubTypeOf(element,'kugel_std');`);
      parts = FilterList(parts,'element',`not HasFeature(element,'f_hallerE');`);
      my ekugel = FilterList(parts,'element',`not Feature(element,'f_hallerE') eq 'true';`)[0];
      if (ekugel) {
        hallerEzones = zones;
      } 
      return hallerEzones;
    }

def montageZonesHallerElectric(groupid) {
      my electriczones = List();
      my zones = call montageZones(groupid);
      my parts = call groupIdPartList(groupid);
      parts = FilterList(parts,'element',`not IsSubTypeOf(element,'leitgestaenge');`);
      if (parts[0]) {
        electriczones = zones;
      } 
      return electriczones;
    }

def pageCountMontage(groupid) {
      my pagecount = 0;
      my montage = Size(call montageZones(groupid));
      my fuss = Size(call montageZonesFuss(groupid));
      my hallerE = Size(call montageZonesHallerE(groupid));
      my electric = Size(call montageZonesHallerElectric(groupid));
      my inos = Size(call inosMontageZones(groupid));
      pagecount = montage + fuss + hallerE + electric + inos;
      return pagecount;
    }

def pageCountHallerAssembly() {
		  my hallerpagecounts = '';
		  my count = 0;
		  my groupidlist = call partGroupIdList('usm_haller');
		  my pagecount = List();
		  my pagecounts = List();
		  for (my groupid :  groupidlist) {
		     count = call pageCountMontage(groupid);
		     pagecount = List(groupid,count);
		     pagecounts = ListAdd(pagecounts,pagecount);
		  }
		  hallerpagecounts = ToJson(pagecounts);
		  return hallerpagecounts;
		}

def checkVolumeHeigthForMontage(groupid) {
			my layout_hoch = false;
			my volumes = call groupIdVolumeList(groupid);
			my volpos = List();
			my height = 0;
			my volume_sum_list = List();
			my partposx = 0;
			my partposy = 0;
			for (my volume : volumes) {
				ListAdd(volpos,PartPos(volume));
			}
			volpos = CompressTable(volpos,List('x','y'),List());
			for (my  pos : volpos) {
				height = 0;
				volume_sum_list = List();
				for (my volume : volumes) {
					partposx = Round(PartPos(volume)['x']);
					partposy = Round(PartPos(volume)['y']);
					if (partposx EQ Round(pos['x']) AND partposy EQ Round(pos['y'])) {
						volume_sum_list = JoinList(volume_sum_list,volume);
					}
				}
				for (my volume : volume_sum_list) {
					height = height + Feature(volume,'zlength');
				}
				if (height GT 210) {
					layout_hoch = true;
					break;
				}
			}
			return layout_hoch;
		}

def checkPrimoHeigthForMontage(zone) {    
      my primoHoch = false;
      my hochlist = List();
      my parts = zone['parts'];
      my maxHeight = 210;

      hochlist = FilterList(parts,'element',`PartPos(element)['z'] le maxHeight;`);  
      /* Falls die Zonen-Definition auch noch parts der Nachbarpanels erwischt, die höher sind */  
      primoHoch = Size(hochlist) gt 10;

      return primoHoch;
    }

def customerLang(mode) {
    	my custdefaultlang = FromJson(NodeValue(NamedNode('documentsettings'),'cust_orderaddress'))['name','customer_language']['value'];
        my lang = 'de';  
        my langlist = List('de','en','es','fr','it');
        if ( InList(langlist, custdefaultlang )){
           lang = custdefaultlang;
        }
        return lang;
       }

def categoryDrawNot(part,groupid,zone) {
    	my excluded = false;
      my parts = zone['parts'];
      if (Size(parts) gt 3 and Size(call groupIdZones(groupid)) gt 1) {
        excluded = not InList(zone['parts'],part);
      } else {
        excluded = USMPartGroupId(part) ne groupid;
      }
      return excluded;
      }
